var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"여, 여러분, 미하~","JPN":"み、皆さん、ミハ～！","ENG":"H-hi, everyone! It's me, Miya!","TWN":"大…大家好～我是米婭～"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"오늘은…… 하트베리 멤버들이랑 다 같이 그라운드 원 번화가에 쇼핑을 나왔는데요.","JPN":"今日は……ハートベリーのみんなとグラウンド・ワンの繫華街に買い物に来ました。","ENG":"I’m now in the Ground One downtown, shopping with HRT Berry members.","TWN":"我今天……和愛心莓果的成員們一起到G1的鬧區來逛街～"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"보시는 것처럼 너무너무 더워요. 어젯밤에도 열대야 때문에 다들 잠자기 힘드셨죠?","JPN":"ご覧のとおりすっごーく暑いです。昨日も熱帯夜のせいでみんな寝苦しかったでしょう？","ENG":"As you can see, it’s super hot today. I’m sure you all suffered through the tropical night yesterday.","TWN":"天氣真的好熱喔～ 昨天晚上大家應該也都熱到睡不著吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"도시가 전부 찜통이다냥…… 온몸이 땀투성이다냥……","JPN":"都市中が熱湯風呂みたいだにゃ……全身汗だくだにゃあ……","ENG":"The whole city is bwoiling... I’m sweating all owver...","TWN":"整個城市像個烤爐一樣喵……身上都是汗喵……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"매니저, 이런 여름엔 수영장이나 워터 파크가 방송 아이템으로 제격 아냐?","JPN":"マネージャー、こんな夏にはプールやウォーターパークで配信したほうがウケやすいんじゃない？","ENG":"Manager, don’t you think going to a swimming pool or a water park would have worked better in this weather?","TWN":"經紀人！你沒聽過一首歌嗎？每到夏天我要去海邊～～"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"튜브 위에서 줄다리기나 누구 수영복이 제일 섹시한지 투표 받거나!","JPN":"チューブの上で綱引きしたり、誰の水着が一番セクシーなのか投票したりね！","ENG":"We could have played tug of war on swim rings, or had people vote for the sexiest swimsuit.","TWN":"至少也要比個沙灘排球，或是投票看誰的泳裝最性感吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"뭐, 1등은 겨뤄 볼 것도 없이 내 차지겠지만!","JPN":"まあ、結果は見なくてもこのアタシが1位に決まっているけどね！","ENG":"I’m sure I would have won!","TWN":"雖然說沒什麼好比的，因為第一名一定是我！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그만둬. 거기서 더 벗으면 너무 파렴치해.","JPN":"やめたほうがいいよ。それ以上の露出は下品に見えるから。","ENG":"Stop it. You can’t take off any more clothes, shame on you.","TWN":"可以了，怕人家不知道你愛露嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"누구더러 파렴치래. 자기는 달밤에 바니걸 복장으로 뛰어다니다 해외 토픽 올랐으면서.","JPN":"どの口で下品とかいうわけ？　そんなユキは真夜中にバニーガールコスプレで走り回って海外でもニュースになったでしょ。","ENG":"Shame on you yourself. You ran around in a bunny girl suit in the middle of the night and the whole scene went viral.","TWN":"你說誰愛露？不知道是誰穿著兔女郎的衣服到處跑，結果還登上國外頭條呢？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"아자.","JPN":"やったー。（棒読み）","ENG":"Woohoo.","TWN":"呀呵。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"칭찬한 거 아니거든?!","JPN":"別に褒めてないけど！？","ENG":"That wasn’t a compliment!","TWN":"這不是稱讚好嗎？！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아, 아하하……","JPN":"あ、あははは……","ENG":"Ah... Hah hah...","TWN":"喔，呵呵呵……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"지금 실외 온도는 섭씨 38도래요. 오늘부터 전사 휴무인 태스크포스 컴퍼니도 많다네요.","JPN":"現在の外気温は38℃だそうです。今日から臨時休業のタスクフォースカンパニーも多いみたいですね。","ENG":"The outside temperature is 38 Celsius. I heard several TASKFORCE companies shut down operations today.","TWN":"聽說現在室外溫度達到攝氏38度，有很多特遣勢力公司今天開始放假呢～"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그러니까 우리 시청자 여러분들은 외출할 때는 물병 챙기고 그늘 밑으로 다니기. 미야랑 꼭꼭 약속~","JPN":"なので、視聴者の皆さんも外出する時はこまめな水分補給と、なるべく日陰を歩いてくださいね。ミヤと約束ですよ～！","ENG":"So everyone, make sure to bring water bottles with you, and stay in the shade. It’s a promise with Miya!","TWN":"觀眾們～出門在外記得要多喝水，盡量走在陽光曬不到的地方喔，打勾勾～"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네? 나갈 일 없다고요? 하으, 그, 그런 뜻이 아니라요……","JPN":"え？　そもそもお出かけしない？　ふえぇ、そういう意味じゃなくて……","ENG":"What? You’re not going outside because you don’t have any friends? Aww... That was not what I meant...","TWN":"嗯？沒有要出門喔？欸，我的意思是……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그러면 더우니까 여기서 방종하고 숙소로 복귀할게요. 안녕.</color>","JPN":"<color=#ffd34c>それでは、暑いのでこの辺で配信を終了して、寮に戻りますね。バイバーイ。</color>","ENG":"<color=#ffd34c>Well, it’s too hot to go on, so we’re ending the show now. Byebye.</color>","TWN":"<color=#ffd34c>天氣太熱，今天的直播到此為止，我要回宿舍囉！掰掰～</color>"},"stage":{"bg":"SUMMER2_01_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};